meta.script:
{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "Does Lutz Auto Sales accept bad credit?",
      "acceptedAnswer": {"@type":"Answer","text":"Yes! At Lutz Auto Sales we welcome all credit types — good credit, bad credit, and no credit. We work with multiple lenders to find financing solutions that work for your budget."}
    },
    {
      "@type": "Question",
      "name": "Do all cars at Lutz Auto Sales come with a Carfax report?",
      "acceptedAnswer": {"@type":"Answer","text":"Yes, every vehicle at Lutz Auto Sales comes with a full Carfax vehicle history report. We believe in transparent pricing and no surprises."}
    },
    {
      "@type": "Question",
      "name": "Where is Lutz Auto Sales located?",
      "acceptedAnswer": {"@type":"Answer","text":"Lutz Auto Sales is located at 17604 N US Highway 41, Unit 1, Lutz, FL 33549. We serve Tampa, Wesley Chapel, Land O Lakes, Carrollwood, and all of Tampa Bay."}
    },
    {
      "@type": "Question",
      "name": "What are Lutz Auto Sales business hours?",
      "acceptedAnswer": {"@type":"Answer","text":"Monday, Tuesday, Friday: 10am-5:30pm. Wednesday, Thursday: 12pm-5:30pm. Saturday: 9am-12pm. Sunday: Closed."}
    },
    {
      "@type": "Question",
      "name": "Does Lutz Auto Sales specialize in Toyota Prius?",
      "acceptedAnswer": {"@type":"Answer","text":"Yes! Lutz Auto Sales specializes in Toyota Prius and hybrid vehicles. We carry one of the largest selections of pre-owned Prius vehicles in the Tampa Bay area."}
    }
  ]
}

body.script:
const sel=document.getElementById('s-vehicle');
inventory.forEach(c=>{const o=document.createElement('option');o.value=c.id;o.textContent=`${c.year} ${c.make} ${c.model} ${c.trim} — $${c.price.toLocaleString()}`;sel.appendChild(o);});
function submitSchedule(){
  const f=document.getElementById('s-first').value.trim();
  const p=document.getElementById('s-phone').value.trim();
  const e=document.getElementById('s-email').value.trim();
  if(!f||!p||!e){alert('Please fill in Name, Phone and Email.');return;}
  document.getElementById('s-success').style.display='block';
}
// Set min date to today
document.getElementById('s-date').min=new Date().toISOString().split('T')[0];
